  const train_info=useSelector((state)=>state.var.train) 
  const add=(user)=>{

    dispatch(addItem(user))
    console.log()
  }
  
    return (
      <>
         <div>Choose_seat</div>
         <button onClick={()=>add('abir')}>Click</button>
         {todos.map((item,index)=>(
          <p>{item.name}</p>
         ))}
         
      </>
     
  
    )
  }
